import { Routes, Route, Navigate } from "react-router-dom";

import AdminLayout from "./AdminLayout";

import Dashboard from "./pages/admin/Dashboard";
import AddPatient from "./pages/admin/patients/AddPatient";
import PatientVisit from "./pages/admin/visits/PatientVisit";
import EMR from "./pages/admin/emr/EMR";
import Billing from "./pages/admin/billing/Billing";

function App() {
  return (
    <Routes>

      {/* ADMIN LAYOUT */}
      <Route path="/admin" element={<AdminLayout />}>

        {/* DEFAULT OPEN */}
        <Route index element={<Dashboard />} />

        <Route path="dashboard" element={<Dashboard />} />

        <Route path="patients/register" element={<AddPatient />} />

        <Route path="patients/visit" element={<PatientVisit />} />

        <Route path="emr" element={<EMR />} />

        <Route path="billing" element={<Billing />} />

      </Route>

      {/* SAFETY */}
      <Route path="*" element={<Navigate to="/admin" />} />

    </Routes>
  );
}

export default App;
